public class AccidentalOverload {
    static class Animal {
        void speak(String sound) { System.out.println(sound); }
    }
    static class Dog extends Animal {
        void speak(int sound) {   // bug: different parameter type — overload not override
            System.out.println("Woof " + sound);
        }
    }
    public static void main(String[] args) {
        Animal a = new Dog();
        a.speak("Bark");   // calls Animal.speak, not Dog.speak
    }
}
